  }

  function acInsertNode(node) {
    const { blockEl, path, anchorNode, anchorOffset } = ac;
    const sel = blockEl.ownerDocument.defaultView.getSelection();

    // Delete trigger text + query
    if (sel.rangeCount) {
      const delRange = document.createRange();
      delRange.setStart(anchorNode, anchorOffset);
      delRange.setEnd(sel.getRangeAt(0).startContainer, sel.getRangeAt(0).startOffset);
      delRange.deleteContents();
    }

    // Insert at cursor
    const insRange = sel.getRangeAt(0);
    insRange.insertNode(node);

    // Ensure there's a text node after for cursor placement
    if (!node.nextSibling || (node.nextSibling.nodeType !== 3)) {
