    const afterRange = document.createRange();
    afterRange.setStartAfter(node);
    if (node.nextSibling && node.nextSibling.nodeType === 3) {
      afterRange.setStart(node.nextSibling, node.nextSibling.textContent === '\u200B' ? 1 : 0);
