    handleInput(blockEl, path);
  }

  function acInsertTransclusion(fieldResult) {
    const { targetItem } = ac;
    const fieldName = fieldResult.id;

    // Create a :transclusion node — expression embedded in AST, no computed field needed
    const node = document.createElement('span');
    node.contentEditable = 'false';
    node.className = 'doc-transclusion';
    node.dataset.itemId = targetItem.id;
    node.dataset.field = fieldName;
    node.dataset.display = targetItem.label;
    node.textContent = targetItem.label + (fieldName !== 'description' ? '.' + fieldName : '');
    node.style.cssText = 'display: inline-block; background: var(--color-warning-light, #fef3c7); padding: 1px 6px; border-radius: 3px; border: 1px solid var(--color-warning, #f59e0b); font-size: 0.8125em; cursor: default; user-select: none;';

    acInsertNode(node);
  }

  function acDetect(blockEl, path) {
    const sel = blockEl.ownerDocument.defaultView.getSelection();
    if (!sel.rangeCount || !sel.isCollapsed) return;
    const range = sel.getRangeAt(0);
    if (range.startContainer.nodeType !== 3) return;
    const text = range.startContainer.textContent;
    const offset = range.startOffset;
    const before = text.substring(0, offset);

    // {{ → field ref
    if (before.endsWith('{{')) {
      acShow('field', blockEl, path);
      return;
    }
    // @ → item ref (only after start, space, or punctuation)
    if (before.endsWith('@') && (before.length === 1 || /[\s(\[{,;:]/.test(before[before.length - 2]))) {
