    }
  }

  // --- Event handlers ---

  // --- Markdown shortcuts ---

  function checkShortcutOnSpace(blockEl, path) {
    // Only convert top-level paragraphs
    if (path.length !== 1) return false;
    const block = getBlock(path);
    if (tagOf(block) !== ':p') return false;
    const sel = blockEl.ownerDocument.defaultView.getSelection();
    if (!sel.rangeCount || !sel.isCollapsed) return false;
    const range = sel.getRangeAt(0);
    if (range.startContainer.nodeType !== 3) return false;
    const before = range.startContainer.textContent.substring(0, range.startOffset);

    // Ensure nothing before the trigger in the block
    const preRange = document.createRange();
    preRange.setStart(blockEl, 0);
    preRange.setEnd(range.startContainer, 0);
    if (preRange.toString().replace(/\u200B/g, '').length > 0) return false;

    // Collect remaining content after trigger
    const inlineAst = domToInlineAst(blockEl);
    function stripPrefix(len) {
      if (inlineAst.length > 0 && isText(inlineAst[0])) {
        const stripped = inlineAst[0].s.substring(len);
        if (stripped) inlineAst[0] = { s: stripped };
        else inlineAst.shift();
      }
      return inlineAst.length ? inlineAst : [{ s: '' }];
    }

    // # through ###### → heading
    const headingMatch = /^#{1,6}$/.exec(before);
    if (headingMatch) {
      const level = headingMatch[0].length;
      setBlock(path, [':h' + level, ...stripPrefix(level)]);
      renderAllBlocks();
      emitChange();
      requestAnimationFrame(() => focusBlock(path, 0));
      return true;
    }

    // >>> → eval block (Hob expression)
    if (before === '>>>') {
      setBlock(path, [null]); // nil expression — structural editor renders as hole
      renderAllBlocks();
      emitChange();
      return true;
    }

    // > → blockquote
    if (before === '>') {
      const content = stripPrefix(1);
      setBlock(path, [':blockquote', [':p', ...content]]);
      renderAllBlocks();
      emitChange();
      const innerPath = [...path, 0];
      requestAnimationFrame(() => focusBlock(innerPath, 0));
      return true;
    }

    // - or * or + → unordered list
    if (before === '-' || before === '*' || before === '+') {
      // Make sure it's not --- (hr shortcut, handled on Enter)
      const content = stripPrefix(1);
      setBlock(path, [':ul', [':li', [':p', ...content]]]);
      renderAllBlocks();
      emitChange();
      const innerPath = [...path, 0, 0];
      requestAnimationFrame(() => focusBlock(innerPath, 0));
      return true;
    }

    // 1. → ordered list
    const olMatch = /^\d+\.$/.exec(before);
    if (olMatch) {
      const content = stripPrefix(olMatch[0].length);
      setBlock(path, [':ol', [':li', [':p', ...content]]]);
      renderAllBlocks();
      emitChange();
      const innerPath = [...path, 0, 0];
      requestAnimationFrame(() => focusBlock(innerPath, 0));
      return true;
    }

    return false;
  }

  function checkShortcutOnEnter(blockEl, path) {
    // Only convert top-level paragraphs
    if (path.length !== 1) return false;
    const block = getBlock(path);
    if (tagOf(block) !== ':p') return false;
    // Check if the entire block content is a shortcut trigger
    const text = blockEl.textContent.replace(/\u200B/g, '').trim();

    // --- or *** or ___ → horizontal rule
    if (/^-{3,}$|^\*{3,}$|^_{3,}$/.test(text)) {
      setBlock(path, [':hr']);
      // Insert an empty paragraph after the hr
      const parent = getParent(path);
      const childIdx = path[path.length - 1];
      parent.splice(childIdx + 2, 0, [':p', { s: '' }]);
      renderAllBlocks();
      emitChange();
      requestAnimationFrame(() => focusBlock([childIdx + 1], 0));
      return true;
    }

    return false;
  }

  function handleInput(blockEl, path) {
    const inlineAst = domToInlineAst(blockEl);
    const block = getBlock(path);
    const blockTag = block[0];
    setBlock(path, [blockTag, ...(inlineAst.length ? inlineAst : [{ s: '' }])]);
    emitChange();

    // Autocomplete: update query or detect trigger
    if (ac) {
      acUpdateQuery();
    } else {
      acDetect(blockEl, path);
    }
  }

  function handleKeyDown(e, blockEl, path) {
    // Autocomplete navigation
    if (ac) {
      if (e.key === 'ArrowDown') { e.preventDefault(); acNavigate(1); return; }
      if (e.key === 'ArrowUp') { e.preventDefault(); acNavigate(-1); return; }
      if (e.key === 'Enter' || e.key === 'Tab') { e.preventDefault(); acSelect(); return; }
      if (e.key === 'Escape') { e.preventDefault(); acHide(); return; }
