    if (e.key === ' ' && !e.ctrlKey && !e.metaKey && checkShortcutOnSpace(blockEl, path)) {
      e.preventDefault();
      return;
    }

    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      if (checkShortcutOnEnter(blockEl, path)) return;
      const listCtx = getListContext(path);
      if (listCtx) { handleListEnter(blockEl, path, listCtx); return; }
      splitBlock(blockEl, path);
    } else if (e.key === 'Backspace' && !e.shiftKey && !e.metaKey && !e.ctrlKey) {
