        const listCtx = getListContext(path);
        if (listCtx && listCtx.pIdx === 0) {
          e.preventDefault();
          handleListBackspace(blockEl, path, listCtx);
          return;
        }
        const block = getBlock(path);
        const blockTag = tagOf(block);
        const childIdx = path[path.length - 1];

        if (childIdx > 0) {
          const prevPath = [...path.slice(0, -1), childIdx - 1];
          const prevBlock = getBlock(prevPath);
          if (isLeafBlock(tagOf(prevBlock))) {
            // Merge with previous editable sibling
            e.preventDefault();
            mergeWithPrevious(blockEl, path);
          } else if (!isEditableBlock(prevBlock)) {
            // Delete previous non-editable block (hr, eval, code-block)
            e.preventDefault();
            const parent = getParent(path);
            parent.splice(childIdx, 1); // remove previous block (childIdx = prevBlock's AST position + 1)
            renderAllBlocks();
            emitChange();
            requestAnimationFrame(() => focusBlock([childIdx - 1], 0));
          }
        } else if (path.length === 1 && blockTag && blockTag !== ':p' && isLeafBlock(blockTag)) {
