          e.preventDefault();
          block[0] = ':p';
          renderAllBlocks();
          emitChange();
          requestAnimationFrame(() => focusBlock(path, 0));
        }
      }
    } else if (e.key === 'Delete' && !e.shiftKey && !e.metaKey && !e.ctrlKey) {
      if (isCursorAtEnd(blockEl)) {
        const listCtx = getListContext(path);
        if (listCtx && handleListDelete(blockEl, path, listCtx)) {
          e.preventDefault();
          return;
        }
        const parent = getParent(path);
        const childIdx = path[path.length - 1];
        const nextIdx = childIdx + 1;
        if (nextIdx < parent.length - 1) {
          const nextPath = [...path.slice(0, -1), nextIdx];
          const nextBlock = getBlock(nextPath);
          if (isLeafBlock(tagOf(nextBlock))) {
            e.preventDefault();
            mergeWithNext(blockEl, path);
          } else if (!isEditableBlock(nextBlock)) {
            // Delete next non-editable block (hr, eval, code-block)
            e.preventDefault();
            parent.splice(nextIdx + 1, 1);
