      }
    }
  }

  function isCursorAtStart(blockEl) {
    const sel = blockEl.ownerDocument.defaultView.getSelection();
    if (!sel.rangeCount) return false;
    const range = sel.getRangeAt(0);
    if (!range.collapsed) return false;
    const testRange = document.createRange();
    testRange.setStart(blockEl, 0);
    testRange.setEnd(range.startContainer, range.startOffset);
    return testRange.toString().length === 0;
  }

  function isCursorAtEnd(blockEl) {
    const sel = blockEl.ownerDocument.defaultView.getSelection();
    if (!sel.rangeCount) return false;
    const range = sel.getRangeAt(0);
    if (!range.collapsed) return false;
    const testRange = document.createRange();
    testRange.setStart(range.startContainer, range.startOffset);
    testRange.setEnd(blockEl, blockEl.childNodes.length);
    return testRange.toString().replace(/\u200B/g, '').length === 0;
  }

  function splitBlock(blockEl, path) {
    const sel = blockEl.ownerDocument.defaultView.getSelection();
    if (!sel.rangeCount) return;
    const range = sel.getRangeAt(0);
    if (!range.collapsed) range.deleteContents();

    // Clone content before and after cursor
    const beforeRange = document.createRange();
    beforeRange.setStart(blockEl, 0);
    beforeRange.setEnd(range.startContainer, range.startOffset);
    const afterRange = document.createRange();
    afterRange.setStart(range.startContainer, range.startOffset);
    afterRange.setEnd(blockEl, blockEl.childNodes.length);

    const beforeDiv = document.createElement('div');
    beforeDiv.appendChild(beforeRange.cloneContents());
    const afterDiv = document.createElement('div');
    afterDiv.appendChild(afterRange.cloneContents());

    const beforeAst = domToInlineAst(beforeDiv);
    const afterAst = domToInlineAst(afterDiv);
    const block = getBlock(path);
    const blockTag = block[0];

    // Update current block with content before cursor
    setBlock(path, [blockTag, ...(beforeAst.length ? beforeAst : [{ s: '' }])]);

    // Insert new :p after current block in same parent
    const parent = getParent(path);
    const childIdx = path[path.length - 1];
    parent.splice(childIdx + 2, 0, [':p', ...(afterAst.length ? afterAst : [{ s: '' }])]);

    renderAllBlocks();
    emitChange();
    const newPath = [...path.slice(0, -1), childIdx + 1];
    requestAnimationFrame(() => focusBlock(newPath, 0));
  }

  function mergeWithPrevious(blockEl, path) {
    const childIdx = path[path.length - 1];
    if (childIdx === 0) return;

    const prevPath = [...path.slice(0, -1), childIdx - 1];
    const prevBlock = getBlock(prevPath);
    const currBlock = getBlock(path);

    const prevInline = prevBlock.slice(1);
    const cursorOffset = inlineTextLength(prevInline);
    const currInline = currBlock.slice(1);

    const merged = mergeAdjacentText([...prevInline, ...currInline]);
    setBlock(prevPath, [prevBlock[0], ...(merged.length ? merged : [{ s: '' }])]);

    // Remove current block from parent
    const parent = getParent(path);
    parent.splice(childIdx + 1, 1);

    renderAllBlocks();
    emitChange();
    requestAnimationFrame(() => focusBlockAtOffset(prevPath, cursorOffset));
  }

  function mergeWithNext(blockEl, path) {
    const parent = getParent(path);
    const childIdx = path[path.length - 1];
    const nextIdx = childIdx + 1;
    if (nextIdx >= parent.length - 1) return;

    const currBlock = getBlock(path);
    const nextPath = [...path.slice(0, -1), nextIdx];
    const nextBlock = getBlock(nextPath);

    const currInline = currBlock.slice(1);
    const cursorOffset = inlineTextLength(currInline);
    const nextInline = nextBlock.slice(1);

    const merged = mergeAdjacentText([...currInline, ...nextInline]);
    setBlock(path, [currBlock[0], ...(merged.length ? merged : [{ s: '' }])]);

    // Remove next block from parent
    parent.splice(nextIdx + 1, 1);

    renderAllBlocks();
    emitChange();
    requestAnimationFrame(() => focusBlockAtOffset(path, cursorOffset));
  }

  // --- List operations ---

  function getListContext(path) {
    // Detect if this :p is inside a :li inside a :ul/:ol
    if (path.length < 3) return null;
    const liPath = path.slice(0, -1);
    const li = getBlock(liPath);
    if (tagOf(li) !== ':li') return null;
    const listPath = liPath.slice(0, -1);
    const list = getBlock(listPath);
    const listTag = tagOf(list);
    if (listTag !== ':ul' && listTag !== ':ol') return null;
