      pIdx: path[path.length - 1],
      liIdx: liPath[liPath.length - 1],
      liPath, listPath, li, list, listTag
    };
  }

  function handleListEnter(blockEl, path, ctx) {
    const block = getBlock(path);
    const inlineContent = domToInlineAst(blockEl);
    const isEmpty = inlineContent.length === 0 ||
      (inlineContent.length === 1 && isText(inlineContent[0]) &&
       inlineContent[0].s.replace(/\u200B/g, '').trim() === '');

    if (isEmpty && ctx.pIdx === 0 && ctx.li.length <= 2) {
      // Empty :li with only one :p — exit list
      liftListItem(path, ctx, [{ s: '' }]);
