      listParent[listChildIdx + 1] = newP;
      renderAllBlocks();
      emitChange();
      requestAnimationFrame(() => focusBlock(ctx.listPath, 0));
    } else {
      const itemsBefore = ctx.liIdx;
      const itemsAfter = ctx.list.length - 1 - ctx.liIdx;

      if (itemsBefore === 0) {
        // Was first — insert :p before list
        listParent.splice(listChildIdx + 1, 0, newP);
        renderAllBlocks();
        emitChange();
        requestAnimationFrame(() => focusBlock(ctx.listPath, 0));
      } else if (itemsAfter === 0) {
        // Was last — insert :p after list
        listParent.splice(listChildIdx + 2, 0, newP);
        renderAllBlocks();
        emitChange();
        const newPath = [...ctx.listPath.slice(0, -1), listChildIdx + 1];
        requestAnimationFrame(() => focusBlock(newPath, 0));
      } else {
