        const afterLis = ctx.list.splice(ctx.liIdx + 1);
        const newList = [ctx.listTag, ...afterLis];
        listParent.splice(listChildIdx + 2, 0, newP, newList);
        renderAllBlocks();
        emitChange();
        const newPPath = [...ctx.listPath.slice(0, -1), listChildIdx + 1];
        requestAnimationFrame(() => focusBlock(newPPath, 0));
      }
    }
  }

  function handleListBackspace(blockEl, path, ctx) {
    if (ctx.liIdx === 0) {
      // First :li — lift out of list
      const currBlock = getBlock(path);
      liftListItem(path, ctx, currBlock.slice(1));
    } else {
      // Not first :li — merge with previous :li's last leaf block
      const prevLiPath = [...ctx.listPath, ctx.liIdx - 1];
      const prevLi = getBlock(prevLiPath);

      // Find last leaf block in previous :li
      let lastPIdx = -1;
      for (let i = prevLi.length - 1; i >= 1; i--) {
        if (isLeafBlock(tagOf(prevLi[i]))) { lastPIdx = i - 1; break; }
      }

      if (lastPIdx >= 0) {
        const lastPPath = [...prevLiPath, lastPIdx];
        const lastP = getBlock(lastPPath);
        const currBlock = getBlock(path);

        const prevInline = lastP.slice(1);
        const cursorOffset = inlineTextLength(prevInline);
        const currInline = currBlock.slice(1);
        const merged = mergeAdjacentText([...prevInline, ...currInline]);

        setBlock(lastPPath, [lastP[0], ...(merged.length ? merged : [{ s: '' }])]);
        ctx.list.splice(ctx.liIdx + 1, 1);

        renderAllBlocks();
        emitChange();
        requestAnimationFrame(() => focusBlockAtOffset(lastPPath, cursorOffset));
      }
    }
  }

  function handleListIndent(path, ctx) {
    if (ctx.liIdx === 0) return; // Can't indent the first item

    // Remove current :li from list
    const currentLi = ctx.list.splice(ctx.liIdx + 1, 1)[0];

    // Previous :li is at array position liIdx (child index liIdx - 1, +1 for tag)
    const prevLi = ctx.list[ctx.liIdx];

    // Append to existing nested list or create a new one
    const lastChild = prevLi[prevLi.length - 1];
    if (tagOf(lastChild) === ctx.listTag) {
      lastChild.push(currentLi);
    } else {
      prevLi.push([ctx.listTag, currentLi]);
    }

    renderAllBlocks();
    emitChange();

    // Calculate new path for the :p inside the moved :li
    const prevLiPath = [...ctx.listPath, ctx.liIdx - 1];
    const prevLiNode = getBlock(prevLiPath);
    const nestedListChildIdx = prevLiNode.length - 2;
    const nestedListNode = prevLiNode[nestedListChildIdx + 1];
    const movedLiChildIdx = nestedListNode.length - 2;
    const newPPath = [...prevLiPath, nestedListChildIdx, movedLiChildIdx, ctx.pIdx];
    requestAnimationFrame(() => focusBlock(newPPath, 0));
  }

  function handleListOutdent(path, ctx) {
    // Check if nested list (list is inside a :li inside another list)
    if (ctx.listPath.length >= 2) {
      const outerLiPath = ctx.listPath.slice(0, -1);
      const outerLi = getBlock(outerLiPath);
      if (tagOf(outerLi) === ':li') {
        const outerListPath = outerLiPath.slice(0, -1);
        const outerList = getBlock(outerListPath);
        const outerListTag = tagOf(outerList);
        if (outerListTag === ':ul' || outerListTag === ':ol') {
          // Remove :li from nested list
          const currentLi = ctx.list.splice(ctx.liIdx + 1, 1)[0];

          // If nested list is now empty, remove it from outer :li
          if (ctx.list.length <= 1) {
            const nestChildIdx = ctx.listPath[ctx.listPath.length - 1];
            outerLi.splice(nestChildIdx + 1, 1);
          }

          // Insert after the outer :li in the outer list
          const outerLiIdx = outerLiPath[outerLiPath.length - 1];
          outerList.splice(outerLiIdx + 2, 0, currentLi);

          renderAllBlocks();
          emitChange();
          const newPPath = [...outerListPath, outerLiIdx + 1, ctx.pIdx];
          requestAnimationFrame(() => focusBlock(newPPath, 0));
          return;
        }
      }
    }

    // Top-level list — lift item out as :p
    const currBlock = getBlock(path);
    liftListItem(path, ctx, currBlock.slice(1));
  }

  function handleListDelete(blockEl, path, ctx) {
    // Only applies at end of last leaf block in :li when there's a next :li
    for (let i = ctx.pIdx + 2; i < ctx.li.length; i++) {
      if (isLeafBlock(tagOf(ctx.li[i]))) return false; // next leaf sibling exists — default handler
    }
    if (ctx.liIdx >= ctx.list.length - 2) return false; // no next :li

    const nextLi = getBlock([...ctx.listPath, ctx.liIdx + 1]);

    // Find first leaf block in next :li
    let firstPIdx = -1;
    for (let i = 1; i < nextLi.length; i++) {
      if (isLeafBlock(tagOf(nextLi[i]))) { firstPIdx = i - 1; break; }
    }
    if (firstPIdx < 0) return false;

    const currBlock = getBlock(path);
    const nextP = nextLi[firstPIdx + 1];
    const currInline = currBlock.slice(1);
    const cursorOffset = inlineTextLength(currInline);
    const nextInline = nextP.slice(1);
    const merged = mergeAdjacentText([...currInline, ...nextInline]);

    setBlock(path, [currBlock[0], ...(merged.length ? merged : [{ s: '' }])]);
    ctx.list.splice(ctx.liIdx + 2, 1); // remove next :li

    renderAllBlocks();
    emitChange();
    requestAnimationFrame(() => focusBlockAtOffset(path, cursorOffset));
    return true;
  }

  function inlineTextLength(nodes) {
    let len = 0;
    for (const node of nodes) {
      if (isText(node)) {
        len += node.s.length;
      } else if (Array.isArray(node)) {
        const tag = node[0];
        if (tag === ':strong' || tag === ':em' || tag === ':code') {
          for (let i = 1; i < node.length; i++) len += textOf(node[i]).length;
        } else {
          len += 1; // non-editable island
        }
      }
    }
    return len;
  }

  // --- Focus management ---

  function focusBlock(path, offset) {
    const el = editor.querySelector(`[data-block-path="${pathStr(path)}"]`);
    if (!el) return;
    el.focus();
    const sel = el.ownerDocument.defaultView.getSelection();
    const range = document.createRange();
    if (offset === 0 && el.childNodes.length > 0 && el.childNodes[0].nodeType === 3) {
      range.setStart(el.childNodes[0], 0);
    } else {
      range.setStart(el, 0);
    }
    range.collapse(true);
    sel.removeAllRanges();
    sel.addRange(range);
  }

  function focusBlockAtOffset(path, textOffset) {
    const el = editor.querySelector(`[data-block-path="${pathStr(path)}"]`);
    if (!el) return;
    el.focus();
    const sel = el.ownerDocument.defaultView.getSelection();
    const range = document.createRange();
    let remaining = textOffset;
    let found = false;

    function walk(node) {
      if (found) return;
      if (node.nodeType === 3) {
        if (remaining <= node.textContent.length) {
          range.setStart(node, remaining);
          range.collapse(true);
          found = true;
          return;
        }
        remaining -= node.textContent.length;
      } else if (node.nodeType === 1) {
        if (node.contentEditable === 'false') {
          remaining -= 1;
          return;
        }
        for (const child of node.childNodes) {
          walk(child);
          if (found) return;
        }
      }
    }

    walk(el);
    if (!found) {
      range.selectNodeContents(el);
      range.collapse(false);
    }
    sel.removeAllRanges();
    sel.addRange(range);
  }

  function emitChange() {
    if (onChange) onChange(JSON.parse(JSON.stringify(ast)));
  }

  // --- Initialize ---
  renderAllBlocks();
  wrapper.appendChild(editor);
  return wrapper;
}
